mapper.select:
SELECT e.ID , e.USER_ID , e.WS_ID , e.TITLE , e.DESC , e.START_DT , e.END_DT , e.IS_ALL_DAY , e.LOCATION , e.COLOR , e.REGIST_DT , e.UPDT_DT , a.EVENT_ID AS ATTENDEE_EVENT_ID , a.USER_ID AS ATTENDEE_USER_ID , a.STATUS FROM CALENDAR_EVENTS e LEFT JOIN EVENT_ATTENDEES a ON e.ID = a.EVENT_ID WHERE e.USER_ID IN ( SELECT wu.USER_ID FROM WORKSPACE_USER wu WHERE wu.WS_ID = #{workspaceId}
AND wu.USER_ID IN
#{uid}
)
AND e.START_DT <= #{endOfMonth} AND e.END_DT >= #{startOfMonth} ORDER BY e.START_DT ASC, e.IS_ALL_DAY DESC

SELECT e.ID , e.USER_ID , e.WS_ID , e.TITLE , e.DESC , e.START_DT , e.END_DT , e.IS_ALL_DAY , e.LOCATION , e.COLOR , e.REGIST_DT , e.UPDT_DT , a.EVENT_ID AS ATTENDEE_EVENT_ID , a.USER_ID AS ATTENDEE_USER_ID , a.STATUS FROM CALENDAR_EVENTS e LEFT JOIN EVENT_ATTENDEES a ON e.ID = a.EVENT_ID WHERE e.USER_ID IN ( SELECT wu.USER_ID FROM WORKSPACE_USER wu WHERE wu.WS_ID = #{workspaceId}
AND wu.USER_ID IN
#{uid}
)
AND e.START_DT <= CONCAT(#{endOfWeek}, ' 23:59:59') AND e.END_DT >= CONCAT(#{startOfWeek}, ' 00:00:00') ORDER BY e.START_DT ASC, e.IS_ALL_DAY DESC

SELECT e.ID , e.USER_ID , e.WS_ID , e.TITLE , e.DESC , e.START_DT , e.END_DT , e.IS_ALL_DAY , e.LOCATION , e.COLOR , e.REGIST_DT , e.UPDT_DT , a.EVENT_ID AS ATTENDEE_EVENT_ID , a.USER_ID AS ATTENDEE_USER_ID , a.STATUS FROM CALENDAR_EVENTS e LEFT JOIN EVENT_ATTENDEES a ON e.ID = a.EVENT_ID WHERE e.USER_ID IN ( SELECT wu.USER_ID FROM WORKSPACE_USER wu WHERE wu.WS_ID = #{workspaceId}
AND wu.USER_ID IN
#{uid}
)
AND DATE(e.START_DT) <= #{targetDate} AND DATE(e.END_DT) >= #{targetDate} ORDER BY e.IS_ALL_DAY DESC, e.START_DT ASC

mapper.insert:
INSERT INTO CALENDAR_EVENTS ( ID
                            , USER_ID
                            , WS_ID
                            , TITLE
                            , `DESC`
                            , START_DT
                            , END_DT
                            , IS_ALL_DAY
                            , LOCATION
                            , COLOR)
VALUES ( #{id}
       , #{userId}
       , #{wsId}
       , #{title}
       , #{description}
       , #{startDt}
       , #{endDt}
       , #{isAllDay}
       , #{location}
       , #{color})

mapper.update:
UPDATE CALENDAR_EVENTS
SET TITLE      = #{title},
    `DESC`     = #{desc},
    START_DT   = #{startDt},
    END_DT     = #{endDt},
    IS_ALL_DAY = #{isAllDay},
    LOCATION   = #{location},
    COLOR      = #{color}
WHERE ID = #{id}
  AND WS_ID = #{wsId}

UPDATE EVENT_ATTENDEES
SET STATUS = #{status, jdbcType=VARCHAR}
WHERE EVENT_ID = #{eventId, jdbcType=VARCHAR}
  AND USER_ID = #{userId, jdbcType=VARCHAR}
